def analizar_contrato(query: str, contrato: str):
    es_lookup = clasificar_query(query)  # classifier propio
    params = {
        "model": "claude-sonnet-4-6",
        "max_tokens": 16000,
        "messages": [{"role": "user", "content": f"{query}\n\n{contrato}"}],
    }
    if not es_lookup:
        # razonamiento cross-clausula → Extended Thinking
        params["thinking"] = {"type": "enabled", "budget_tokens": 10000}
    return client.messages.create(**params)
